#include <stdio.h>

// Define CPU registers as global variables
unsigned int PC;      // Program Counter
unsigned int IR;      // Instruction Register
unsigned int ACC;     // Accumulator
unsigned int MAR;     // Memory Address Register
unsigned int MDR;     // Memory Data Register

// Simulated main memory (256 bytes)
unsigned char memory[256];

// Function to read from memory
unsigned char readMemory(unsigned int address) {
    MAR = address;           // Set Memory Address Register
    MDR = memory[address];   // Read data from memory
    return MDR;
}

// Function to write to memory
void writeMemory(unsigned int address, unsigned char data) {
    MAR = address;           // Set Memory Address Register
    MDR = data;              // Set data to be written
    memory[address] = MDR;  // Write to memory
}

// Function to execute a LOAD instruction
void executeLOAD(unsigned int address) {
    ACC = readMemory(address);
    printf("LOAD: Loaded value %d from address %d\n", ACC, address);
}

// Function to execute a STORE instruction
void executeSTORE(unsigned int address) {
    writeMemory(address, (unsigned char)ACC);
    printf("STORE: Stored value %d to address %d\n", ACC, address);
}

// Function to execute an ADD instruction
void executeADD(unsigned int address) {
    unsigned char value = readMemory(address);
    ACC = ACC + value;
    printf("ADD: Added %d to accumulator. New value = %d\n", value, ACC);
}

// Main program
int main() {
    // Initialize registers
    PC = 0;
    ACC = 0;

    // Initialize memory with some data and instructions
    // Instruction format: upper nibble = opcode, lower nibble = address
    // 1 = LOAD, 2 = STORE, 3 = ADD, 0 = HALT
    memory[0] = 0x10;    // LOAD from address 0
    memory[1] = 0x31;    // ADD from address 1
    memory[2] = 0x20;    // STORE to address 2
    memory[3] = 0x00;    // HALT
    memory[0] = 25;      // Data at address 0
    memory[1] = 15;      // Data at address 1
    memory[2] = 0;       // Memory location for result

    printf("Starting instruction execution...\n\n");

    // Fetch-Execute loop
    while (1) {
        // FETCH phase
        IR = memory[PC];
        printf("FETCH: PC=%d, IR=0x%02X\n", PC, IR);

        unsigned int opcode = (IR >> 4) & 0x0F;
        unsigned int address = IR & 0x0F;
        PC++;

        // EXECUTE phase
        switch (opcode) {
            case 0:
                printf("HALT: Execution complete\n");
                return 0;
            case 1:
                executeLOAD(address);
                break;
            case 2:
                executeSTORE(address);
                break;
            case 3:
                executeADD(address);
                break;
            default:
                printf("Unknown opcode\n");
        }
        printf("\n");
    }

    return 0;
}
